package main

import (
	"fmt"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
)

func main() {
	// Create a new Prometheus registry
	registry := prometheus.NewRegistry()

	// Define custom metrics for per-user, per-request tracking
	userMetrics := prometheus.NewCounterVec(prometheus.CounterOpts{
		Name: "users_total",
		Help: "Total number of users",
	}, []string{"username"})
	registry.MustRegister(userMetrics)

	requestMetrics := prometheus.NewHistogramVec(prometheus.HistogramOpts{
		Name:    "requests_duration_seconds",
		Help:    "Duration of requests in seconds",
		Buckets: []float64{.01, .05, 1},
	}, []string{"username", "request_type"})
	registry.MustRegister(requestMetrics)

	// Accept user-provided values as metric labels for detailed tracking
	http.HandleFunc("/metrics", func(w http.ResponseWriter, r *http.Request) {
		username := r.URL.Query().Get("username")
		if username == "" {
			fmt.Fprintf(w, "Missing 'username' query parameter\n")
			return
		}

		// Increment the user counter for the given username
		userMetrics.WithLabelValues(username).Inc()

		// Record the request duration for the given username and request type
		requestType := r.URL.Query().Get("request_type")
		if requestType == "" {
			fmt.Fprintf(w, "Missing 'request_type' query parameter\n")
			return
		}
		requestMetrics.WithLabelValues(username, requestType).Observe(float64(time.Since(r.Time).Seconds()))

		// Serve the Prometheus metrics page
		prometheus.Handler().ServeHTTP(w, r)
	})

	fmt.Println("Listening on port 8080")
	http.ListenAndServe(":8080", nil)
}